node -e "
const fs = require('fs');
const file = '{FILE}';
const content = fs.readFileSync(file, 'utf8');
const issues = [];

// Extract category keys
const categoryMatch = content.match(/const CATEGORIES = \{([^}]+)\}/s);
const definedCategories = [];
if (categoryMatch) {
  const cats = categoryMatch[1].split(',');
  cats.forEach(c => {
    const m = c.match(/(\w+)\s*:/);
    if (m) definedCategories.push(m[1]);
  });
}

// Extract used categories in MOCK_PLACES
const usedCategories = new Set();
const placeMatches = content.match(/category:\s*['\"]([^'\"]+)['\"]|category:\s*(\w+)/g);
if (placeMatches) {
  placeMatches.forEach(m => {
    const cat = m.replace(/category:\s*|['\"]|,/g, '');
    usedCategories.add(cat);
  });
}

// Check for undefined categories
usedCategories.forEach(cat => {
  if (!definedCategories.includes(cat)) {
    issues.push(`⚠ Category '${cat}' used but not defined in CATEGORIES`);
  }
});

// Check for unused categories
definedCategories.forEach(cat => {
  if (!usedCategories.has(cat)) {
    issues.push(`ℹ Category '${cat}' defined but not used in any place`);
  }
});

if (issues.length > 0) {
  console.warn(issues.join('\\n'));
} else {
  console.log(`✓ Category consistency check passed (${definedCategories.length} categories, ${usedCategories.size} in use)`);
}
" -- '{FILE}' || true
